+fn verify_qe_identity(quote: &ParsedQuote, qe_identity: &str) -> Result<()> {
+    let identity: QeIdentity = serde_json::from_str(qe_identity).map_err(|_| Error::InvalidQeIdentity)?;
+
+    // Enforce that the QE report matches the expected Intel QE identity.
+    if quote.qe_report.mrsigner != identity.enclave_identity.mrsigner {
+        return Err(Error::InvalidQeIdentity);
+    }
+
+    if quote.qe_report.isvprodid != identity.enclave_identity.isvprodid {
+        return Err(Error::InvalidQeIdentity);
+    }
+
+    let tcb_level = identity
+        .enclave_identity
+        .tcb_levels
+        .iter()
+        .find(|level| level.tcb.isvsvn <= quote.qe_report.isvsvn)
+        .ok_or(Error::InvalidQeIdentity)?;
+
+    if tcb_level.tcb_status != "UpToDate" && tcb_level.tcb_status != "SWHardeningNeeded" {
+        return Err(Error::InvalidQeIdentity);
+    }
+
+    // Apply miscselect/miscselectMask constraints.
+    if (quote.qe_report.miscselect & identity.enclave_identity.miscselect_mask)
+        != (identity.enclave_identity.miscselect & identity.enclave_identity.miscselect_mask)
+    {
+        return Err(Error::InvalidQeIdentity);
+    }
+
+    // Apply attributes/attributesMask constraints.
+    if (quote.qe_report.attributes.flags & identity.enclave_identity.attributes_mask.flags)
+        != (identity.enclave_identity.attributes.flags & identity.enclave_identity.attributes_mask.flags)
+    {
+        return Err(Error::InvalidQeIdentity);
+    }
+
+    if (quote.qe_report.attributes.xfrm & identity.enclave_identity.attributes_mask.xfrm)
+        != (identity.enclave_identity.attributes.xfrm & identity.enclave_identity.attributes_mask.xfrm)
+    {
+        return Err(Error::InvalidQeIdentity);
+    }
+
+    Ok(())
+}
